/**
 * Almanacco Contadino Regionalizzato - Database Completo
 * 365 giorni di proverbi agricoli italiani con varianti dialettali per 20 regioni
 * Ogni giorno include: proverbio nazionale, varianti regionali, eventi, consigli lunari, lavori specifici
 */

export interface RegionalContent {
  dialetto?: string; // Proverbio in dialetto regionale
  traduzione?: string; // Traduzione italiana se dialetto poco comprensibile
  proverbio: string; // Proverbio italiano standard per la regione
  spiegazione: string;
  lavoriSpecifici?: string[]; // Lavori consigliati per quella zona climatica
  fonte?: string;
}

export interface LunarAdvice {
  crescente?: string; // Consiglio se luna crescente
  calante?: string; // Consiglio se luna calante
  piena?: string; // Consiglio se luna piena
  nuova?: string; // Consiglio se luna nuova
}

export interface AlmanaccoEntry {
  giorno: number; // 1-31
  mese: number; // 1-12
  nazionale: {
    proverbio: string;
    spiegazione: string;
    fonte?: string;
  };
  regioni?: Record<string, RegionalContent>; // Key: nome regione normalizzato (es. 'basilicata', 'puglia')
  evento?: string; // Evento speciale del giorno (santo, festività, etc.)
  santo?: string; // Santo del giorno
  luna?: LunarAdvice; // Consigli lunari specifici
  curiosita?: string; // Curiosità storica/culturale
  lavoriSpecifici?: string[]; // Lavori consigliati generici (se non specificati per regione)
}

